const today = new Date();
today.setHours(0, 0, 0, 0);

const overdue = items.filter(item => {
  const row = item.json;

  if (!row.deadline) return false;

  const deadline = new Date(row.deadline);
  deadline.setHours(0, 0, 0, 0);

  const status = (row.status || '').trim();
  const escalated = (row.escalated_at || '').toString().trim();

  const isActiveStatus = ['Pending', 'Doing', 'Overdue'].includes(status);
  const isOverdue = deadline < today;
  const notEscalated = escalated === '';

  return isActiveStatus && isOverdue && notEscalated;
});

return overdue;

items.sort((a, b) => {
  const priorityA = a.json.priority === 'High' ? 0 : 1;
  const priorityB = b.json.priority === 'High' ? 0 : 1;

  if (priorityA !== priorityB) {
    return priorityA - priorityB;
  }

  const deadlineA = new Date(a.json.deadline);
  const deadlineB = new Date(b.json.deadline);

  return deadlineA - deadlineB;
});

return items;

const total = items.length;
const high = items.filter(item => item.json.priority === 'High').length;
const normal = items.filter(item => item.json.priority === 'Normal').length;

const reportDate = new Date().toISOString().split('T')[0];

return [
  {
    json: {
      total_overdue: total,
      high_count: high,
      normal_count: normal,
      report_date: reportDate,
      tasks: items.map(item => item.json),
    }
  }
];

const tasks = $json.tasks || [];

const lines = tasks.map((task, index) => {
  return `${index + 1}. [${task.priority}] ${task.task_name} | Owner: ${task.owner_name || '-'} | Deadline: ${task.deadline} | Status: ${task.status}`;
});

const reportBody = `
WEEKLY OVERDUE TASK REPORT

Report Date: ${$json.report_date}

Total overdue tasks: ${$json.total_overdue}
High priority tasks: ${$json.high_count}
Normal priority tasks: ${$json.normal_count}

Task Details:
${lines.join('\n')}
`;

return [
  {
    json: {
      ...$json,
      report_body: reportBody
    }
  }
];
